import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import Sidebar from '../../components/Sidebar';
import Navbar from '../../components/Navbar';
import LoadingSpinner from '../../components/LoadingSpinner';
import axios from 'axios';
import toast from 'react-hot-toast';
import { FiUploadCloud, FiFile, FiX, FiLink, FiPlus, FiSend, FiClock, FiCheckCircle } from 'react-icons/fi';

const API = 'http://localhost:5000/api';

const SubmitAssignment = () => {
  const [assignments, setAssignments] = useState([]);
  const [mySubmissions, setMySubmissions] = useState([]);
  const [selectedAssignment, setSelectedAssignment] = useState(null);
  const [files, setFiles] = useState([]);
  const [urls, setUrls] = useState([]);
  const [urlInput, setUrlInput] = useState('');
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const fileRef = useRef();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [aRes, sRes] = await Promise.all([
        axios.get(`${API}/assignments`),
        axios.get(`${API}/submissions/my`)
      ]);
      setAssignments(aRes.data);
      setMySubmissions(sRes.data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const isSubmitted = (assignmentId) => {
    return mySubmissions.some(s => s.assignment?._id === assignmentId || s.assignment === assignmentId);
  };

  const handleFileSelect = (e) => {
    const newFiles = Array.from(e.target.files);
    setFiles(prev => [...prev, ...newFiles]);
  };

  const removeFile = (index) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const addUrl = () => {
    if (urlInput.trim()) {
      setUrls(prev => [...prev, urlInput.trim()]);
      setUrlInput('');
    }
  };

  const removeUrl = (index) => {
    setUrls(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedAssignment) return toast.error('Select an assignment');
    if (files.length === 0 && urls.length === 0 && !text.trim()) {
      return toast.error('Please add files, URLs, or text');
    }

    setSubmitting(true);
    try {
      const formData = new FormData();
      formData.append('assignment', selectedAssignment._id);
      formData.append('text', text);
      formData.append('urls', JSON.stringify(urls));
      files.forEach(file => formData.append('files', file));

      await axios.post(`${API}/submissions`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      toast.success('Assignment submitted successfully!');
      setFiles([]); setUrls([]); setText(''); setSelectedAssignment(null);
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Submission failed');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <LoadingSpinner />;

  return (
    <div className="page-container">
      <Sidebar />
      <div className="main-content" style={{ paddingTop: '90px' }}>
        <Navbar />

        <motion.div className="page-header" initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}>
          <h1>📝 Assignments</h1>
          <p>View and submit your assignments</p>
        </motion.div>

        <div className="content-grid">
          {/* Assignment List */}
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <h3 style={{ marginBottom: '15px', fontFamily: 'Poppins', color: 'var(--text-primary)' }}>
              Available Assignments
            </h3>
            {assignments.map((assignment, i) => (
              <motion.div
                key={assignment._id}
                className="card"
                style={{
                  marginBottom: '12px', cursor: 'pointer',
                  borderColor: selectedAssignment?._id === assignment._id ? 'var(--primary)' : undefined,
                  boxShadow: selectedAssignment?._id === assignment._id ? '0 0 20px rgba(102, 126, 234, 0.2)' : undefined
                }}
                onClick={() => !isSubmitted(assignment._id) && setSelectedAssignment(assignment)}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.05 }}
                whileHover={{ scale: 1.01 }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                  <div>
                    <h4 style={{ marginBottom: '6px', color: 'var(--text-primary)' }}>{assignment.title}</h4>
                    <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginBottom: '8px' }}>
                      {assignment.description?.substring(0, 100)}...
                    </p>
                    <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                      <span className="badge badge-primary">{assignment.subject}</span>
                      <span className="badge badge-info">
                        <FiClock size={10} /> Due: {new Date(assignment.dueDate).toLocaleDateString()}
                      </span>
                      <span className="badge badge-warning">Marks: {assignment.totalMarks}</span>
                    </div>
                  </div>
                  {isSubmitted(assignment._id) && (
                    <span className="badge badge-success"><FiCheckCircle /> Submitted</span>
                  )}
                </div>
              </motion.div>
            ))}
          </motion.div>

          {/* Submit Form */}
          <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }}>
            {selectedAssignment ? (
              <div className="card">
                <h3 style={{ marginBottom: '20px', fontFamily: 'Poppins' }}>
                  Submit: {selectedAssignment.title}
                </h3>

                <form onSubmit={handleSubmit}>
                  {/* File Upload */}
                  <div className="form-group">
                    <label className="form-label">Upload Files (Photos, PDFs, Docs)</label>
                    <div
                      className="upload-area"
                      onClick={() => fileRef.current.click()}
                    >
                      <FiUploadCloud className="upload-icon" />
                      <h3>Click to upload files</h3>
                      <p>Supports images, PDFs, docs (max 50MB each)</p>
                    </div>
                    <input
                      type="file"
                      ref={fileRef}
                      style={{ display: 'none' }}
                      multiple
                      onChange={handleFileSelect}
                      accept="image/*,.pdf,.doc,.docx,.zip,.rar"
                    />
                    {files.length > 0 && (
                      <div className="file-list">
                        {files.map((file, i) => (
                          <div key={i} className="file-item">
                            <div className="file-info">
                              <FiFile className="file-icon" />
                              <span style={{ fontSize: '0.85rem' }}>{file.name}</span>
                            </div>
                            <button className="remove-btn" onClick={() => removeFile(i)}>
                              <FiX />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* URL Input */}
                  <div className="form-group">
                    <label className="form-label">Add URLs</label>
                    <div className="url-input-group">
                      <input
                        type="url"
                        className="form-input"
                        placeholder="https://example.com"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                      />
                      <button type="button" className="btn btn-outline btn-sm" onClick={addUrl}>
                        <FiPlus />
                      </button>
                    </div>
                    {urls.length > 0 && (
                      <div className="url-list">
                        {urls.map((url, i) => (
                          <div key={i} className="url-item">
                            <a href={url} target="_blank" rel="noreferrer"><FiLink /> {url}</a>
                            <button className="remove-btn" onClick={() => removeUrl(i)}>
                              <FiX />
                            </button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Text */}
                  <div className="form-group">
                    <label className="form-label">Additional Notes</label>
                    <textarea
                      className="form-textarea"
                      placeholder="Add any notes or description..."
                      value={text}
                      onChange={(e) => setText(e.target.value)}
                    />
                  </div>

                  <motion.button
                    type="submit"
                    className="btn btn-primary btn-block btn-lg"
                    disabled={submitting}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                  >
                    {submitting ? (
                      <div className="loading-spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }} />
                    ) : (
                      <><FiSend /> Submit Assignment</>
                    )}
                  </motion.button>
                </form>
              </div>
            ) : (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-icon">📋</div>
                  <h3>Select an Assignment</h3>
                  <p>Click on an assignment from the list to start submitting</p>
                </div>
              </div>
            )}
          </motion.div>
        </div>
      </div>
    </div>
  );
};

export default SubmitAssignment;
